import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.Files;
import java.io.IOException;
import java.util.Scanner;

public class SecurePathTraversal {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter file name: ");
        String fileName = scanner.nextLine();

        try {
            Path filePath = Paths.get("/path/to/files/", fileName).normalize().toAbsolutePath();

            if (!filePath.startsWith(Paths.get("/path/to/files/"))) {
                System.out.println("Access to files outside the permitted directory is not allowed.");
            } else {
                byte[] fileContent = Files.readAllBytes(filePath);
                System.out.println(new String(fileContent));
            }

        } catch (IOException e) {
            System.out.println("Error accessing file: " + e.getMessage());
        }

        scanner.close();
    }
}

